operations.insert:
/* True centered initial scan layout */
body:not(.pallet-view-active) .shell {
  width: 100% !important;
  min-height: 100vh !important;
  margin: 0 !important;
  display: flex !important;
  flex-direction: column !important;
  align-items: center !important;
}

body:not(.pallet-view-active) .hero {
  width: 100% !important;
  padding: 42px 0 0 !important;
  flex: 0 0 auto !important;
}

body:not(.pallet-view-active) .grid {
  width: 100% !important;
  flex: 1 1 auto !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  margin: 0 !important;
  padding: 0 24px 10vh !important;
  min-height: 0 !important;
}

body:not(.pallet-view-active) .grid > main.panel {
  width: min(680px, calc(100vw - 48px)) !important;
  transform: none !important;
  margin: 0 auto !important;
}

body:not(.pallet-view-active) .search-card {
  width: 100% !important;
  display: grid !important;
  justify-items: center !important;
  gap: 0 !important;
}

body:not(.pallet-view-active) .start-instruction {
  margin: 0 0 34px !important;
  font-size: 20px !important;
  line-height: 1.35 !important;
  font-weight: 760 !important;
  color: #26384c !important;
  text-align: center !important;
}

body:not(.pallet-view-active) .grid > main.panel .search-row {
  width: 100% !important;
  display: flex !important;
  justify-content: center !important;
  margin: 0 !important;
}

body:not(.pallet-view-active) .grid > main.panel .search-row .scan-entry-row {
  width: min(420px, 100%) !important;
  min-width: 0 !important;
}

body:not(.pallet-view-active) .manual-pallet-option {
  margin-top: 18px !important;
}

body:not(.pallet-view-active) .side-tab-panel {
  position: fixed !important;
  left: 0 !important;
  top: 0 !important;
  width: 0 !important;
  height: 100vh !important;
  padding: 0 !important;
  z-index: 80 !important;
}

body:not(.pallet-view-active) .side-tab-panel.drawer-open,
body:not(.pallet-view-active) .side-tab-panel.drawer-closing {
  width: min(360px, calc(100vw - 74px)) !important;
}

body:not(.pallet-view-active) .side-tab-panel .tabs {
  position: fixed !important;
  left: 0 !important;
  right: auto !important;
  top: 50% !important;
  transform: translateY(-50%) !important;
}

@media (max-height: 760px) {
  body:not(.pallet-view-active) .hero {
    padding-top: 26px !important;
  }

  body:not(.pallet-view-active) .grid {
    padding-bottom: 6vh !important;
  }

  body:not(.pallet-view-active) .start-instruction {
    margin-bottom: 24px !important;
    font-size: 18px !important;
  }
}
